\tikzset{pics/myOA/.style={
code={
\coordinate (-NodeMinus) at (0,0) {};
\coordinate (-NodePlus) at (0,3) {};
\coordinate (-NodeOut) at (6,1.5) {};

%% input resistor
\draw(-NodeMinus) node[above]{$-$}
to[short, o-] ++(1,0) node[below]{$-$}
to[R, l_=$R_i$] (1,3) node[above]{$+$}
to[short, -o] (-NodePlus) node[below]{$+$};

