\draw(-NodeOut)
to[short, o-] ++(-1,0) -- ++(0,1)
to[R,l_=$R_o$] ++(-2,0)
to[american controlled voltage source, l=$A\cdot v_d$] ++(0,-2.5) node[ground]{};

