alias=tmp@name,
postaction={%
insert path={
\pgfextra{%
\pgfpointdiff{\pgfpointanchor{\pgf@node@name}{center}}%
{\pgfpointanchor{\pgf@node@name}{east}}%
\pgfmathsetmacro\insiderad{\pgf@x}
\fill[#1] (\pgf@
[email protected]
) ([xshift=-\pgflinewidth]\pgf@
[email protected]
) arc
(0:180:\insiderad-\pgflinewidth)--cycle;
\fill[#2] (\pgf@
[email protected]
) ([xshift=\pgflinewidth]\pgf@
[email protected]
) arc
(180:360:\insiderad-\pgflinewidth)--cycle; }}}}}
\makeatother

\def\addquote
{%
\Large
\begin{tabular}[b]{p{5cm}}
\midrule
\textit{Wir m\"ussen wissen.}\\
\textit{Wir werden wissen.}\\
\mbox{}\hfill\large\textsc{David Hilbert}\\
\midrule
\end{tabular}%
}

\def\alicegraphic
{%
\begin{tikzpicture}
\clip (0,0) circle (2.7cm);
\node (0,0) {\includegraphics[width=5cm]{alice}};
