\usepackage{luatex85} % compatibilidad pdfTeX → LuaTeX (DEBE ir primero)
\usepackage{graphicx}
\usepackage[Export]{adjustbox}
\usepackage{pgffor}
\usepackage{expl3}

% ── Activar sintaxis expl3 ───────────────────────────────────────────────────
\ExplSyntaxOn

% ── Variable entera local ────────────────────────────────────────────────────
\int_new:N \l__score_pagecount_int

% ── Comando público ──────────────────────────────────────────────────────────
\NewDocumentCommand \InsertarScore { m }
{
\__score_insertar:n { #1 }
}

% ── Implementación interna ───────────────────────────────────────────────────
\cs_new_protected:Nn \__score_insertar:n
{
% ── Paso 1: Contar páginas ──────────────────────────────────────────────
%
% \pdfximage (provisto por luatex85) registra el archivo en el
% diccionario interno de imágenes de LuaTeX y actualiza el contador
% \pdflastximagepages sin emitir ningún contenido visible.
%
% En LuaTeX nativo (sin luatex85) esto equivale a:
% \pdfextension ximage { #1 }
% \pdffeedback lastximagepages
%
\pdfximage { #1 }
\int_set:Nn \l__score_pagecount_int { \pdflastximagepages }

% ── Paso 2: Bucle página a página ──────────────────────────────────────
%
% ##1 → índice del bucle (se tokeniza a #1 al ejecutarse).
% Cada iteración inserta una página y añade \par como separador.
%
\int_step_inline:nn { \l__score_pagecount_int }
{
\includegraphics
[
page = ##1 ,
width = \linewidth ,
]
{ #1 }
\par
}
}

