Here below is the simple example to insert every page with
\includegraphics
, with
the help of Ulrike Fischer
:

\documentclass{book}
\usepackage{graphicx}
\usepackage{lipsum}
\begin{document}

\chapter{AAAA}
\section{AAAA}

\lipsum[4-6]

% https://tex.stackexchange.com/a/641479/322482
\ExplSyntaxOn
\graphics_get_pagecount:nN {example-image-a4-numbered.pdf} \l_tmpa_tl
\int_step_inline:nn {\l_tmpa_tl} {
\includegraphics[width=4.5cm,page=#1]{example-image-a4-numbered.pdf}\par
}
\ExplSyntaxOff

\lipsum[4-6]
\end{document}

