from pypdf import PdfReader, PdfWriter
import os

def split_pdf_page_dash(input_pdf, output_dir="output_pages"):
os.makedirs(output_dir, exist_ok=True)

reader = PdfReader(input_pdf)
total = len(reader.pages)

for i in range(total):
page_num = i + 1
writer = PdfWriter()
writer.add_page(reader.pages[i])

out_path = os.path.join(output_dir, f"page-{page_num}.pdf")
with open(out_path, "wb") as f:
writer.write(f)

print(f"Created {total} files in '{output_dir}'")

split_pdf_page_dash("main.pdf")

