\documentclass{standalone}
\usepackage[3d]{luadraw}
\usepackage{fourier}
\usepackage[svgnames]{xcolor}
\begin{document}

\begin{luadraw*}{name=sphere_diagram}
local ld = luadraw
local pt3d = ld.pt3d
local M, Mc, vecK = pt3d.M, pt3d.Mc, pt3d.vecK
local pi = math.pi
local g = ld.graph3d:new{
window3d={-3,3,-3,3,-3,3},
viewdir={0,75}, size={10,10}
}
local RR = 3
require 'luadraw_spherical'
ld.Hiddenlines = false
g:Define_sphere({
radius=RR, color="",
edgewidth=6,edgecolor="black"
})
local z0, theta = 1.2, pi
local Rz = (RR^2 - z0^2)^0.5

local O, N = M(0, 0, z0), M(0, 0, RR)
local P = Mc(Rz, pi/2, z0)
local R = Mc(Rz, -pi/6, z0)
local C = Mc(Rz, 3*pi/2, z0)

g:DSbigcircle({ld.sM(0, 90), ld.sM(90, 90)})
g:DScircle({O, vecK}, {style="dashed"})
g:Dseg3d({O, P}, "thick")
g:DSarc({N,R},1,{width=12,color="blue"})

g:DSlabel(
"$N$", N, {pos="N"},
"$O$", O, {pos="W"},
"$r$", (O+P)/2, {pos="N"},
"$C$", C, {pos="W"}
)
g:Dspherical()
g:Ddots3d({O,R,P,N})
g:Dlabel3d("$R$", M(-1,-1,2), {node_options="text=blue"})
g:Show()
\end{luadraw*}

