\documentclass[tikz,margin=1cm]{standalone}
\begin{document}
\begin{tikzpicture}
\draw[gray!50] (-8,0) grid (8,-8);
\fill (0,0) node[above=12pt]{origin} circle (5pt);
\draw[ultra thick] (-6,0) arc[x radius=12,y radius=8,start angle=90,end angle=0] -- (-6,-8) -- cycle;
